PyTorch入门-4 优化模型参数1234567891011121314151617181920212223242526272829303132333435363738394041import torchfrom torch import nnfrom torch.utils.data import DataLoaderfrom torchvision import datasetsfrom torchvision.transforms import ToTensor, Lambdatraining_data = datasets.FashionMNIST( root=&quot;data&quot;, train=True, download=True, transform=ToTensor())test_data = datasets.FashionMNIST( root=&quot;data&quot;, train=False, download=True, transform=ToTensor())train_dataloader = DataLoader(training_data, batch_size=64)test_dataloader = DataLoader(test_data, batch_size=64)class NeuralNetwork(nn.Module): def __init__(self): super(NeuralNetwork, self).__init__() self.flatten = nn.Flatten() self.linear_relu_stack = nn.Sequential( nn.Linear(28*28, 512), nn.ReLU(), nn.Linear(512, 512), nn.ReLU(), nn.Linear(512, 10), ) def forward(self, x): x = self.flatten(x) logits = self.linear_relu_stack(x) return logitsmodel = NeuralNetwork() 超参数123learning_rate = 1e-3batch_size = 64epochs = 5 循环优化一旦我们设置了超参数，我们就可以通过优化循环训练和优化我们的模型。优化循环的每次迭代称为epoch 每个epoch由两个主要部分组成: 训练循环：遍历训练数据集，并试图收敛到最优参数。 验证/测试循环：对测试数据集进行迭代，以检查模型性能是否正在改善。 损失函数 nn.MSELoss: 均方误差，回归问题 nn.NLLLoss: 负对数似然，分类问题 nn.CrossEntropyLoss: 结合nn.LogSoftmax and nn.NLLLoss 12# Initialize the loss functionloss_fn = nn.CrossEntropyLoss() 优化算法 SGD ADAM RMSProp … 1optimizer = torch.optim.SGD(model.parameters(), lr=learning_rate) 在训练循环中，优化分为三个步骤: 调用optimizer.zero_grad()重置模型参数的梯度。梯度默认情况下是叠加的; 为了防止重复计算，我们在每次迭代时显式地将它们归零。 通过调用loss.backward()反向传播预测损失。Pytorch保存loss关于每个变量的梯度 一旦我们有了梯度，我们调用optimizer.step()来通过向后传递中收集的梯度来调整参数。 Full Implementation1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859def train_loop(dataloader, model, loss_fn, optimizer): size = len(dataloader.dataset) for batch, (X, y) in enumerate(dataloader): # Compute prediction and loss pred = model(X) loss = loss_fn(pred, y) # Backpropagation optimizer.zero_grad() loss.backward() optimizer.step() if batch % 100 == 0: loss, current = loss.item(), batch * len(X) print(f&quot;loss: &#123;loss:&gt;7f&#125; [&#123;current:&gt;5d&#125;/&#123;size:&gt;5d&#125;]&quot;)def test_loop(dataloader, model, loss_fn): size = len(dataloader.dataset) num_batches = len(dataloader) test_loss, correct = 0, 0 with torch.no_grad(): #预测不需要计算梯度 for X, y in dataloader: pred = model(X) test_loss += loss_fn(pred, y).item() correct += (pred.argmax(1) == y).type(torch.float).sum().item() test_loss /= num_batches correct /= size print(f&quot;Test Error: 
 Accuracy: &#123;(100*correct):&gt;0.1f&#125;%, Avg loss: &#123;test_loss:&gt;8f&#125; 
&quot;) loss_fn = nn.CrossEntropyLoss()optimizer = torch.optim.SGD(model.parameters(), lr=learning_rate)epochs = 10for t in range(epochs): print(f&quot;Epoch &#123;t+1&#125;
-------------------------------&quot;) train_loop(train_dataloader, model, loss_fn, optimizer) test_loop(test_dataloader, model, loss_fn)print(&quot;Done!&quot;)###### outputEpoch 1-------------------------------loss: 2.290156 [ 0/60000]loss: 2.275099 [ 6400/60000]loss: 2.256799 [12800/60000]loss: 2.252760 [19200/60000]loss: 2.235528 [25600/60000]loss: 2.205756 [32000/60000]loss: 2.204928 [38400/60000]loss: 2.172354 [44800/60000]loss: 2.160271 [51200/60000]loss: 2.127511 [57600/60000]Test Error: Accuracy: 49.9%, Avg loss: 2.116347 保存并加载模型12import torchimport torchvision.models as models 保存加载模型权重PyTorch模型将学习到的参数存储在一个名为state_dict的内部状态字典中。 12model = models.vgg16(pretrained=True)torch.save(model.state_dict(), &#x27;model_weights.pth&#x27;) 要加载模型权重，您需要首先创建同一个模型的实例，然后使用load_state_dict()方法加载参数。 12345model = models.vgg16() # we do not specify pretrained=True, i.e. do not load default weights#我们没有指定pretraining =True，即不加载默认的权重model.load_state_dict(torch.load(&#x27;model_weights.pth&#x27;))model.eval() #be sure to call model.eval() method before inferencing to set the dropout and batch normalization layers to evaluation mode. Failing to do this will yield inconsistent inference results.#在推断将退出和批处理规范化层设置为求值模式之前，请确保调用model.eval()方法。如果不这样做，将产生不一致的推理结果。 Saving and Loading Models with Shapes1234# 当加载模型权重时，我们需要首先实例化模型类，因为类定义了网络的结构。我们可能希望将这个类的结构与模型一起保存，在这种情况下，我们可以将model(而不是model.state_dict())传递给保存函数torch.save(model, &#x27;model.pth&#x27;)model = torch.load(&#x27;model.pth&#x27;) Demo 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152import torchimport torch.nn as nnimport torch.optim as optimclass Net(nn.Module): def __init__(self): super(Net, self).__init__() self.conv1 = nn.Conv2d(3, 6, 5) self.pool = nn.MaxPool2d(2, 2) self.conv2 = nn.Conv2d(6, 16, 5) self.fc1 = nn.Linear(16 * 5 * 5, 120) self.fc2 = nn.Linear(120, 84) self.fc3 = nn.Linear(84, 10) def forward(self, x): x = self.pool(F.relu(self.conv1(x))) x = self.pool(F.relu(self.conv2(x))) x = x.view(-1, 16 * 5 * 5) x = F.relu(self.fc1(x)) x = F.relu(self.fc2(x)) x = self.fc3(x) return xnet = Net()print(net)optimizer = optim.SGD(net.parameters(), lr=0.001, momentum=0.9)# Additional informationEPOCH = 5PATH = &quot;model.pt&quot;LOSS = 0.4torch.save(&#123; &#x27;epoch&#x27;: EPOCH, &#x27;model_state_dict&#x27;: net.state_dict(), &#x27;optimizer_state_dict&#x27;: optimizer.state_dict(), &#x27;loss&#x27;: LOSS, &#125;, PATH)model = Net()optimizer = optim.SGD(net.parameters(), lr=0.001, momentum=0.9)checkpoint = torch.load(PATH)model.load_state_dict(checkpoint[&#x27;model_state_dict&#x27;])optimizer.load_state_dict(checkpoint[&#x27;optimizer_state_dict&#x27;])epoch = checkpoint[&#x27;epoch&#x27;]loss = checkpoint[&#x27;loss&#x27;]model.eval()# - or -model.train()

PyTorch入门-3 建立神经网络每个Module都是nn.Module的子类 123456789import osimport torchfrom torch import nnfrom torch.utils.data import DataLoaderfrom torchvision import datasets, transforms#检查GPU是否可以使用device = &#x27;cuda&#x27; if torch.cuda.is_available() else &#x27;cpu&#x27;print(f&#x27;Using &#123;device&#125; device&#x27;) 定义类即神经网络模块123456789101112131415161718192021222324252627282930313233343536373839class NeuralNetwork(nn.Module): #nn.Module的子类 def __init__(self): super(NeuralNetwork, self).__init__() self.flatten = nn.Flatten() self.linear_relu_stack = nn.Sequential( nn.Linear(28*28, 512), nn.ReLU(), nn.Linear(512, 512), nn.ReLU(), nn.Linear(512, 10), ) def forward(self, x): #在forward方法中实现对输入数据的操作 x = self.flatten(x) logits = self.linear_relu_stack(x) return logits #我们创建一个NeuralNetwork的实例，并将其移动到设备上(GPU/CPU)，然后打印其结构model = NeuralNetwork().to(device)print(model)output:NeuralNetwork( (flatten): Flatten(start_dim=1, end_dim=-1) (linear_relu_stack): Sequential( (0): Linear(in_features=784, out_features=512, bias=True) (1): ReLU() (2): Linear(in_features=512, out_features=512, bias=True) (3): ReLU() (4): Linear(in_features=512, out_features=10, bias=True) ))######X = torch.rand(1, 28, 28, device=device) #输入数据X，输出数据logitslogits = model(X) #不能直接调用model.forward()pred_probab = nn.Softmax(dim=1)(logits) #使用softmax获取概率y_pred = pred_probab.argmax(1)print(f&quot;Predicted class: &#123;y_pred&#125;&quot;) 各层详解12input_image = torch.rand(3,28,28) #模拟3张28*28的图片print(input_image.size()) #output：torch.Size([3, 28, 28]) nn.Flatten123flatten = nn.Flatten() #展平，将28*28的矩阵转化为784的向量flat_image = flatten(input_image)print(flat_image.size()) #output: torch.Size([3, 784]) nn.Linear123layer1 = nn.Linear(in_features=28*28, out_features=20) #使用存储的权重和偏差对输入应用线性转换。hidden1 = layer1(flat_image)print(hidden1.size()) #output: torch.Size([3, 20]) nn.Relu1hidden1 = nn.ReLU()(hidden1) #激活函数 nn.SequentialSequential是模块的有序容器，数据按照定义的顺序传递给所有模块 12345678seq_modules = nn.Sequential( flatten, layer1, nn.ReLU(), nn.Linear(20, 10))input_image = torch.rand(3,28,28)logits = seq_modules(input_image) nn.Softmax12softmax = nn.Softmax(dim=1)pred_probab = softmax(logits) 模型参数nn.Module自动跟踪参数，可以使用parameters() or named_parameters()访问参数 1234print(&quot;Model structure: &quot;, model, &quot;

&quot;)for name, param in model.named_parameters(): print(f&quot;Layer: &#123;name&#125; | Size: &#123;param.size()&#125; | Values : &#123;param[:2]&#125; 
&quot;) Autograd在训练神经网络时，最常用的算法是反向传播。在该算法中，参数(模型权值)根据损失函数相对于给定参数的梯度进行调整。为了计算这些梯度，PyTorch内置了一个名为torch.autograd的差异化引擎。它支持自动计算梯度的任何计算图 12345678import torchx = torch.ones(5) # input tensory = torch.zeros(3) # expected outputw = torch.randn(5, 3, requires_grad=True)b = torch.randn(3, requires_grad=True) #等价：b = torch.randn(3); b.requires_grad_(True)z = torch.matmul(x, w)+bloss = torch.nn.functional.binary_cross_entropy_with_logits(z, y) w,b是参数，需要loss函数对这两个变量求梯度，所以requires_grad=True，反向传播函数存储在grad_fn中 123456print(&#x27;Gradient function for z =&#x27;, z.grad_fn)print(&#x27;Gradient function for loss =&#x27;, loss.grad_fn)loss.backward() #只能使用一次，如果想多次使用，使得retain_graph=Trueprint(w.grad)print(b.grad) 停止梯度追踪12345678910z = torch.matmul(x, w)+bprint(z.requires_grad) #output: Truewith torch.no_grad(): z = torch.matmul(x, w)+b print(z.requires_grad) #output: Falsez = torch.matmul(x, w)+bz_det = z.detach()print(z_det.requires_grad) #output: False 停止计算的原因： 将神经网络中的一些参数标记为冻结参数。这是对预先训练的网络进行微调的一个非常常见的场景 在只进行正向传递的情况下加快计算速度，因为在不跟踪梯度的张量上的计算将更加有效 关于计算图的信息从概念上讲，autograd在由Function对象组成的有向无环图(DAG)中保存数据(张量)和所有执行的操作(以及产生的新张量)的记录。在这个DAG中，叶是输入张量，根是输出张量。通过跟踪这个从根到叶的图形，您可以使用链式规则自动计算梯度。 forward 运行请求的操作来计算结果张量 在DAG中保持操作的梯度函数。 backward：.backward()在DAG根目录上被调用，开始autograd() 计算每个.grad_fn的梯度 将它们累加到各自张量的.grad属性中 利用链式法则，一直传播到叶张量 12345678910111213141516171819202122232425262728293031inp = torch.eye(5, requires_grad=True)out = (inp+1).pow(2)out.backward(torch.ones_like(inp), retain_graph=True)print(&quot;First call
&quot;, inp.grad)out.backward(torch.ones_like(inp), retain_graph=True)print(&quot;
Second call
&quot;, inp.grad)inp.grad.zero_()out.backward(torch.ones_like(inp), retain_graph=True)print(&quot;
Call after zeroing gradients
&quot;, inp.grad)###outputFirst call tensor([[4., 2., 2., 2., 2.], [2., 4., 2., 2., 2.], [2., 2., 4., 2., 2.], [2., 2., 2., 4., 2.], [2., 2., 2., 2., 4.]])Second call tensor([[8., 4., 4., 4., 4.], [4., 8., 4., 4., 4.], [4., 4., 8., 4., 4.], [4., 4., 4., 8., 4.], [4., 4., 4., 4., 8.]])Call after zeroing gradients tensor([[4., 2., 2., 2., 2.], [2., 4., 2., 2., 2.], [2., 2., 4., 2., 2.], [2., 2., 2., 4., 2.], [2., 2., 2., 2., 4.]])

PyTorch入门 QuickStart加载数据PyTorch有两个操作数据的包：DataLoader/Dataset. Dataset存储样本和他们的标签，DataLoader 负责在Dataset上构造一个迭代器，并支持批处理，采样，打乱，多线程。 TorchVision Dataset包含两个参数:transform和target_transform，分别修改样本和标签 123456789101112131415161718192021222324252627282930313233import torchfrom torch import nnfrom torch.utils.data import DataLoaderfrom torchvision import datasetsfrom torchvision.transforms import ToTensor, Lambda, Composeimport matplotlib.pyplot as plt# Download training data from open datasets.training_data = datasets.FashionMNIST( root=&quot;data&quot;, train=True, download=True, transform=ToTensor(),)# Download test data from open datasets.test_data = datasets.FashionMNIST( root=&quot;data&quot;, train=False, download=True, transform=ToTensor(),)batch_size = 64# Create data loaders.train_dataloader = DataLoader(training_data, batch_size=batch_size)test_dataloader = DataLoader(test_data, batch_size=batch_size)for X, y in test_dataloader: print(&quot;Shape of X [N, C, H, W]: &quot;, X.shape) print(&quot;Shape of y: &quot;, y.shape, y.dtype) break 创建model定义nn.Module的子类，使其成为我们想要的神经网络，我们在__init__函数中定义网络的各个层，并在forward函数中指定数据如何通过网络 12345678910111213141516171819202122232425# Get cpu or gpu device for training.device = &quot;cuda&quot; if torch.cuda.is_available() else &quot;cpu&quot;print(f&quot;Using &#123;device&#125; device&quot;)# Define modelclass NeuralNetwork(nn.Module): def __init__(self): super(NeuralNetwork, self).__init__() self.flatten = nn.Flatten() self.linear_relu_stack = nn.Sequential( nn.Linear(28*28, 512), nn.ReLU(), nn.Linear(512, 512), nn.ReLU(), nn.Linear(512, 10) ) def forward(self, x): x = self.flatten(x) logits = self.linear_relu_stack(x) return logitsmodel = NeuralNetwork().to(device)print(model) 优化模型参数（Loss、梯度下降）12345678910111213141516171819202122232425262728293031323334353637383940414243loss_fn = nn.CrossEntropyLoss() #定义损失函数：交叉熵函数optimizer = torch.optim.SGD(model.parameters(), lr=1e-3) #梯度下降的方法def train(dataloader, model, loss_fn, optimizer): size = len(dataloader.dataset) model.train() for batch, (X, y) in enumerate(dataloader): X, y = X.to(device), y.to(device) # Compute prediction error pred = model(X) loss = loss_fn(pred, y) # Backpropagation optimizer.zero_grad() loss.backward() optimizer.step() if batch % 100 == 0: loss, current = loss.item(), batch * len(X) print(f&quot;loss: &#123;loss:&gt;7f&#125; [&#123;current:&gt;5d&#125;/&#123;size:&gt;5d&#125;]&quot;) def test(dataloader, model, loss_fn): size = len(dataloader.dataset) num_batches = len(dataloader) model.eval() test_loss, correct = 0, 0 with torch.no_grad(): for X, y in dataloader: X, y = X.to(device), y.to(device) pred = model(X) test_loss += loss_fn(pred, y).item() correct += (pred.argmax(1) == y).type(torch.float).sum().item() test_loss /= num_batches correct /= size print(f&quot;Test Error: 
 Accuracy: &#123;(100*correct):&gt;0.1f&#125;%, Avg loss: &#123;test_loss:&gt;8f&#125; 
&quot;) epochs = 5for t in range(epochs): print(f&quot;Epoch &#123;t+1&#125;
-------------------------------&quot;) train(train_dataloader, model, loss_fn, optimizer) test(test_dataloader, model, loss_fn)print(&quot;Done!&quot;) 保存模型12torch.save(model.state_dict(), &quot;model.pth&quot;)print(&quot;Saved PyTorch Model State to model.pth&quot;) 加载模型加载模型的过程包括重新创建模型结构和将状态字典加载到模型中 12345678910111213141516171819202122model = NeuralNetwork()model.load_state_dict(torch.load(&quot;model.pth&quot;))classes = [ &quot;T-shirt/top&quot;, &quot;Trouser&quot;, &quot;Pullover&quot;, &quot;Dress&quot;, &quot;Coat&quot;, &quot;Sandal&quot;, &quot;Shirt&quot;, &quot;Sneaker&quot;, &quot;Bag&quot;, &quot;Ankle boot&quot;,]model.eval()x, y = test_data[0][0], test_data[0][1]with torch.no_grad(): pred = model(x) predicted, actual = classes[pred[0].argmax(0)], classes[y] print(f&#x27;Predicted: &quot;&#123;predicted&#125;&quot;, Actual: &quot;&#123;actual&#125;&quot;&#x27;) Tensors初始化123456789101112131415161718192021222324252627282930313233343536373839404142data = [[1, 2],[3, 4]]x_data = torch.tensor(data)np_array = np.array(data)x_np = torch.from_numpy(np_array)x_ones = torch.ones_like(x_data) # retains the properties of x_dataprint(f&quot;Ones Tensor: 
 &#123;x_ones&#125; 
&quot;)x_rand = torch.rand_like(x_data, dtype=torch.float) # overrides the datatype of x_dataprint(f&quot;Random Tensor: 
